var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"어서 오세요, 경정님. 오늘도 일찍 나오셨네요.","JPN":"おはようございます、警視様。今日も早いですね。","ENG":"Good morning, Major. You're early as usual.","TWN":"歡迎，警正大人，今天也好早啊。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"경찰이라면 당연히 시간을 준수해야지.","JPN":"警察官たる者、時間は厳守しないと。","ENG":"I'm a police officer: I must be punctual.","TWN":"警察當然要守時了。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그런데 그 포스터는 다 뭐야?","JPN":"ところで、そのポスターはなに？","ENG":"By the way, what are those posters?","TWN":"那些海報是什麼？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이번에 저희가 붙이러 다녀야 될 현상수배서죠.","JPN":"今から私たちが貼らなければならない指名手配書です。","ENG":"Wanted posters, for you and I to put up out there today.","TWN":"是我們這次要張貼的懸賞通緝令。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"리플레이서 사태 이후로 인력이 없어서 지지부진한 사건들이 꽤 늘었잖아요.","JPN":"リプレイサーの事件以降、人手不足で\\n捜査が進まない事件がかなり増えてきたじゃないですか。","ENG":"Since the Replacer incident, we've been slow at solving crimes due to a lack of manpower.","TWN":"克隆事件發生後，我們人手不足，導致很多案件毫無進展。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그 얘기는 들었어. 시민들의 협조를 받으려고 한단 말이지.","JPN":"その話は聞いた。それで市民に協力を求めるわけね。","ENG":"So I've heard. And that's why we're going to ask the citizens for help.","TWN":"這我也聽說了，是想要尋求市民的幫助吧。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......그런데 인력이 부족하다면서 우리는 왜 수배서나 붙이러 다녀야 되는 거야?","JPN":"……ところで、人手不足だと言ってるのに\\nなんで指名手配書なんか貼りに行かなきゃならないの？","ENG":"But if manpower is the problem, shouldn't we use ours to solve crimes, rather than putting up these posters?","TWN":"……可是妳都說人手不足了，為什麼我們還要去貼通緝令呢？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그야 이런 일로 농땡이 피워야 무서운 악당들이랑 싸우는 데 안 끌려 가니까요.","JPN":"この仕事を口実にしておくと、怖い悪党と戦う現場に\\n呼び出されなくて済むんです。","ENG":"Nope. We need this, to avoid getting dragged into fights with scary villains.","TWN":"因為這樣就可以偷懶，不用去和可怕的壞人戰鬥了啊。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"자자, 경정님도 오셨겠다 얼른 가죠!","JPN":"さあ、警視様も出勤したことですし、早く行きましょう！","ENG":"Alright, now that you're here, let's go!","TWN":"好了，警正大人既然也來了，那我們快出發吧！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"거기 서지 못해! 강소영 경위!","JPN":"待ちなさい！　マエカワ警部補！","ENG":"Stop right there! Lieutenant Kang!","TWN":"站住！姜素英警衛！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>연쇄 동물 납치범을 찾습니다. 실종된 동물들을 목격하신 분은 관할 경찰서로 연락 주세요</color>......","JPN":"<color=#ffd34c>連続動物拉致事件の容疑者を捜しています。\\n失踪した動物たちを目撃した方は管轄の警察署までご連絡ください</color>……","ENG":"<color=#ffd34c>Wanted: A serial animal abductor. If you believe you've witnessed animal abduction, please contact your local police station</color>...","TWN":"<color=#ffd34c>尋找動物連環綁架犯。若目擊到失蹤的動物，請聯絡管轄區的警察局</color>……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"호진 언니, 이 포스터 어디서 났어요?","JPN":"マユミさん、このポスターどこでもらいました？","ENG":"Hojin, where did you get this poster?","TWN":"鎬眞姐，這個海報是從哪來的？"},"stage":{"bg":"CLASS","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L23_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"우리 동네 여기저기에 잔뜩 붙어 있었어.","JPN":"そこでもらったの。街のあちこちにいっぱい貼られてたから。","ENG":"It was put up here and there in the neighborhood.","TWN":"我們家附近到處都貼滿了這個海報。"},"stage":{"bg":"CLASS","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"어른들이 그러는데 며칠 전에 알렉산더도 사라졌대.","JPN":"大人たちが言ってたけど、数日前にアレクサンダーも消えたって。","ENG":"Some grownups said that Alexander also disappeared a few days ago.","TWN":"我聽大人們說，幾天前，亞歷山大也失蹤了。"},"stage":{"bg":"CLASS","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"알렉산더는 누군가, 호진 대원?","JPN":"マユミ隊員、アレクサンダーとは誰のことだ？","ENG":"Who's this Alexander, Operative Hojin?","TWN":"亞歷山大是誰啊，鎬眞隊員？"},"stage":{"bg":"CLASS","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"야채 가게 할아버지가 키우는 웰시 코기. 우리 동네 귀여움 일등이야.","JPN":"八百屋のおじいさんが飼ってるウェルシュ・コーギーだよ。\\nこの街で一番可愛いの。","ENG":"The greengrocer's Welsh Corgi. He's the cutest thing in the neighborhood.","TWN":"是蔬菜店爺爺養的一隻柯基犬，在我們街上是超級可愛的狗狗。"},"stage":{"bg":"CLASS","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"여기 사진도 찍어 뒀어. 볼래?","JPN":"写真があるんだけど、見る？","ENG":"Here, I've got his photo, too. Want to see?","TWN":"我這裡有照片，要看嗎？"},"stage":{"bg":"CLASS","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"오오...... 괴, 굉장히 사랑스러운 털뭉치다......","JPN":"おぉ……す、すごく可愛らしいモフモフだな……","ENG":"Ooh... S-such an adorable-looking furball!","TWN":"噢噢……好、好可愛的小毛團……"},"stage":{"bg":"CLASS","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"이렇게 귀여운 강아지를 납치해 가다니, 나쁜 사람들 짓이 분명해!","JPN":"こんなに可愛い犬をさらうなんて、きっと悪い人たちの仕業だよ！","ENG":"Whoever has kidnapped this cute dog, he's got to be a bad person.","TWN":"竟然綁架這麼可愛的小狗，一定是壞人做的！"},"stage":{"bg":"CLASS","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"사라진 동물들을 찾아서 다시 보금자리로 돌려 보내 주자!","JPN":"いなくなった動物たちを探し出して、家に帰してあげよう！","ENG":"Let's find the missing animals and send them back home!","TWN":"讓我們找到失蹤的動物，送它們回家吧！"},"stage":{"bg":"CLASS","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"들었나, 스미스 병장. 새롭게 태어난 심판의 탄환을 선보일 기회다.","JPN":"聞いたか、スミス兵長。生まれ変わった審判の弾丸を披露するチャンスだ。","ENG":"Hear that, Sergeant Smith? We've got a chance to showcase our newborn bullets of punishment.","TWN":"聽到了嗎，史密斯兵長，這是讓嶄新的審判子彈亮相的機會。"},"stage":{"bg":"CLASS","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"좋아, 그럼 지금 바로 알렉산더를 찾으러 가자!","JPN":"よし、それじゃあ今すぐアレクサンダーを探しに行こう！","ENG":"Alright, then let's go find Alexander now!","TWN":"好，我們現在就去找亞歷山大吧！"},"stage":{"bg":"CLASS","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"앗, 역시 호진 언니! 무슨 단서가 있어요?","JPN":"さすがマユミさん！　何か手がかりがあるんですか？","ENG":"Ooo, yes, Hojin! So, got any leads?","TWN":"啊，不愧是鎬眞姐姐！有什麼線索嗎？"},"stage":{"bg":"CLASS","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"아니? 모르는데? 어디로 가면 돼?","JPN":"うーん、わからないかも。どこに行けばいいかな？","ENG":"Erm, no. Where do we start?","TWN":"沒有啊？我不知道，應該去哪裡找呀？"},"stage":{"bg":"CLASS","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"음...... 폰으로 찾아 보니까 호진 언니네 말고도 여기저기서 같은 일이 일어났대요.","JPN":"うーん……スマホで調べてみたら、\\nいろんなところで同じような事件が起きたって。","ENG":"Mm... I checked on my phone, and the same thing has happened in many other places as well.","TWN":"唔……我用手機查了一下，除了鎬眞姐姐家之外，其他地方也發生了同樣的事情。"},"stage":{"bg":"CLASS","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"정말? 그럼 여러 명일 수도 있겠네?","JPN":"本当に？　じゃあ、複数人による犯行かもしれないよね。","ENG":"Really? Then, there could be multiple perps.","TWN":"真的嗎？這麼說犯人可能有好幾個囉？"},"stage":{"bg":"CLASS","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"네. 저희끼리만 갔다가 누가 다치기라도 하면......","JPN":"はい。僕たちだけで行って、もし誰か怪我でもしたら……","ENG":"Yes. This could be too dangerous for just the three of us to handle, too.","TWN":"沒錯，就我們幾個去，萬一出了事……"},"stage":{"bg":"CLASS","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"후, 후훗...... 그렇다면 어쩔 수 없지.","JPN":"ふ、ふふっ……なら、仕方ないか。","ENG":"Hah, hah hah. I guess we don't have a choice, then.","TWN":"呵，呵呵……那沒辦法了。"},"stage":{"bg":"CLASS","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"베테랑인 본관은 문제없지만, 하림 대장과 호진 대원의 안전을 위해 작전은 재고해야겠군.","JPN":"ベテランである本官は問題ないが、\\nウサギ隊長とマユミ隊員の安全のために、作戦は再考することにしよう。","ENG":"I could handle it just fine, but I understand if you two are too worried to carry on with it.","TWN":"像本官這種老兵是沒什麼問題的，但為了夏琳隊長和鎬眞隊員的安全，這個作戰得重新考慮一下了。"},"stage":{"bg":"CLASS","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"맞다! 좋은 생각 났어!","JPN":"そうだ！　いいこと思いついた！","ENG":"Oooh, I've got a good idea!","TWN":"對了！我想到了一個好主意！"},"stage":{"bg":"CLASS","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"짠! 도착!","JPN":"ジャーン！　到着！","ENG":"Tah-dah! We're here!","TWN":"鏘鏘！到了！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"와, 여기 학생회 건물 맞죠? 처음 와 봐요!","JPN":"わぁ、ここって生徒会の建物ですよね？　初めて来ました！","ENG":"Whoa, this is the Student Council building, right? I've never been here before!","TWN":"哇，這是學生會大樓吧？我還是第一次來呢！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"그런데 언니, 우리 이렇게 마음대로 들어와도 돼요?","JPN":"ところで、マユミさん。勝手に入っていいんですか？","ENG":"But Hojin, are you sure we can get in without telling anyone?","TWN":"不過姐姐，我們這樣隨便進來，真的沒問題嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"응. 곤란한 일이 생기면 언제든지 찾아오라고 사부가 알려 줬거든.","JPN":"うん。困ったことがあったらいつでも訪ねて来いと\\n師匠が教えてくれたの。","ENG":"Yes. Master told me to come whenever I needed her help.","TWN":"嗯，我師父說過，遇到麻煩可以隨時來找她。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"사부......?","JPN":"師匠……？","ENG":"Master?","TWN":"師父……？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"거기 멈추시죠, 학생들.","JPN":"お待ちなさい。","ENG":"Stay where you are, students.","TWN":"同學，給我站住。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_QM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"옥상이다! 저격수인가! 다들 엄폐하도록!","JPN":"屋上だ！　狙撃手か！　みんな、隠れろ！","ENG":"A possible sniper on the rooftop! Everyone, take cover!","TWN":"在屋頂！是狙擊手嗎！全員找掩護！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"소림아, 철봉 뒤에 숨어도 다 보여.","JPN":"ミズキちゃん、鉄棒の後ろに隠れても丸見えだよ。","ENG":"Sorim, we can see you hiding behind that pole.","TWN":"蕭林，躲在單杠後面也看得到喔。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"신성한 학생회에 아무것도 모르는 어린 후배들을 데려 오다니 놀랍군요.","JPN":"神聖なる生徒会に、何も知らない\\n若い後輩たちを連れてくるとは驚きました。","ENG":"You dared bring ignorant juniors to the sacred ground of the Student Council.","TWN":"你竟然把年幼的後輩帶到了神聖的學生會。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_QM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"자기 행동 때문에 무슨 일이 일어날지 각오했다는 의미로 받아들여도 되겠죠?","JPN":"自分の行動の結果として何が起きても\\n覚悟はできている、という意味にとらえてもよいでしょうか？","ENG":"Can I take it that you're prepared for the consequences, whatever they are?","TWN":"妳的行動會引起怎麼樣的結果，我就當作妳已經有心理準備了。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_QM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HARIM_RABBIT_SORIM_BOTH","text":{"KOREA":"꿀꺽......","JPN":"ごくり……","ENG":"*Gulp*","TWN":"吞口水……"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_QM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"와아! 과자가 엄청나게 많아!","JPN":"わあ！　お菓子がいっぱいある！","ENG":"Whoa, so many cookies!","TWN":"哇！餅乾多到令人不敢相信！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"달콤한 음식은 긴장을 풀어주죠.","JPN":"甘いものは緊張をほぐしてくれます。","ENG":"Sweet food helps you relax.","TWN":"甜食可以緩解緊張的情緒。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_QM_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"후배 손님들을 위해 항상 넉넉히 준비해 두고 있으니 많이들 먹어요.","JPN":"後輩のお客さんのためにいつもたっぷり\\n用意してますので、好きなだけどうぞ。","ENG":"I always have some on hand for guests like you. Please, help yourselves.","TWN":"這些是隨時專為你們這些後輩準備的，多吃點吧。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_QM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"잘 먹을게요, 사부!","JPN":"いただきます、師匠！","ENG":"Thank you, Master!","TWN":"謝謝你，師父！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"네? 이 언니가 호진 언니가 말한 사부님이세요?","JPN":"え？　このお姉さんがマユミさんの言っていた師匠ですか？","ENG":"Err? Hojin, is she the Master you told us about?","TWN":"嗯？這個姐姐就是鎬眞姐說的師父嗎？"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"응. 그리고 우리 아카데미의 총학생회장이야.","JPN":"うん。そしてアカデミーの生徒会長なのよ。","ENG":"Yes. She's also the Student President of the Academy.","TWN":"對，也是我們學院的學生會長。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"총학생회장이요? 정말?","JPN":"生徒会長なんですか？　本当に？","ENG":"The Student President? Really?","TWN":"學生會長？真的嗎？"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"옌 싱 란체스터라고 해요.","JPN":"イェン・シング・ランチェスターと申します。","ENG":"My name is Yen Xing Lanchester.","TWN":"我叫嫣杏·蘭賈斯特。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"근래 처리할 업무가 많다 보니 새로 온 전학생과 인사를 나눌 여유도 없었군요.","JPN":"近頃は業務が多くて新しい転校生に挨拶する暇もなかったんです。","ENG":"I've been so busy working that I didn't have time to say hello to you new transfer students.","TWN":"最近很多事務，都沒有時間問候新來的轉校生。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"학생회장으로서 충분히 노력하고 있다고 생각했지만, 저도 아직 멀었네요.","JPN":"生徒会長として十分努力していると\\n思っていましたが、私もまだまだですね。","ENG":"Clearly, I'm not as good Student President as I thought I was.","TWN":"身為學生會長，我雖然自認為很努力，但還遠遠不夠呢。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"앗, 아니에요.","JPN":"いえっ、そんなことないです。","ENG":"Oh, no.","TWN":"啊，沒這種事。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"그보다 멋대로 들어와서 혼날 거라고 생각했는데, 이렇게 챙겨 주셔서 놀랐어요.","JPN":"それより、勝手に入っちゃって怒られると\\n思ったんですが、歓迎いただいて驚きました。","ENG":"I'm surprised for your unexpected hospitality. I thought you'd punish us for sneaking in.","TWN":"本來以為妳會因為我們擅自闖入生氣，沒想到妳卻這麼照顧我們。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"그게 바로 사부의 매력이지.","JPN":"それが師匠の魅力だよ。","ENG":"That's exactly why I like her.","TWN":"這就是我師父的魅力。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"분위기는 항상 무겁고 진지해 보이지만 사실 엄청 착하거든.","JPN":"いつもクールで真面目に見えるけど、とても優しいの。","ENG":"She always looks stern and serious, but she's actually very kind and friendly.","TWN":"雖然她看起來很嚴肅，但其實是非常善良的。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"예전부터 제 인상 때문인지 학생들이 절 대하기 어려워하더군요.","JPN":"昔からそのような印象のせいか、生徒たちが私と接しにくいようでした。","ENG":"It's probably the way I look that keeps other students away.","TWN":"從以前開始，學生們就因為我的形象，都有些怕我。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"게다가 학생들이 친근감을 가지고 다가와야 할 학생회도 딱딱한 이미지로 굳어 버렸죠.","JPN":"そのせいで生徒に親しまれるべき生徒会も\\n堅いイメージになってしまいました。","ENG":"And my position in the Student Council as well.","TWN":"也因此，本來該與學生保持親近的學生會，形象也變得非常嚴肅死板。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그래서 요즘은 학생들과 더 가까워지기 위해 아까처럼 직접 마중 나가곤 한답니다.","JPN":"ですので、もっと親しんでいただけるよう、\\n最近は先ほどのように直接出迎えたりもします。","ENG":"So, I've been trying to receive them in person like I did with you earlier, to get close to them.","TWN":"所以為了拉近和學生的距離，我會像剛才一樣親自出去迎接。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"아하......","JPN":"なるほど……","ENG":"Aha.","TWN":"原來如此……"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"하림 양은 좀 전부터 저를 똑바로 보지 못하는 것 같은데.","JPN":"ウサギさんは、さっきから私と目を合わせてくれないようですが。","ENG":"Harim, I've noticed you're avoiding eye contact with me.","TWN":"從剛才開始，夏琳好像就一直不敢直視我。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아직도 제가 어렵게 느껴지나요?","JPN":"まだ私のことを接しにくいと感じているでしょうか？","ENG":"Am I still making you feel uncomfortable?","TWN":"還是覺得我很難以親近嗎？"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"앗, 아뇨! 무척 친절한 분이라고 생각해요!","JPN":"あっ、いいえ！　とても親切な方だと思います！","ENG":"Oh, no. I think you're very kind.","TWN":"啊，不是的！我覺得妳非常親切！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"저어...... 그런데 항상 그렇게 과감한 옷차림으로 다니세요?","JPN":"あの……ところで、いつもそんなに大胆な服装なんですか？","ENG":"But erm... do you always wear bold clothes like those?","TWN":"只是……妳平時也穿得如此開放嗎？"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"저희 아카데미는 복식의 자유를 존중하기 위해 교복 착용을 강제하지 않기로 했어요.","JPN":"私たちのアカデミーは服装の自由を\\n尊重するために、制服を強制しないことにしました。","ENG":"The Academy has decided not to force its uniform on its students; to respect their freedom of dress.","TWN":"本學院尊重學生的穿著自由，不會強制要求學生穿校服。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"저 또한 학생들의 다양한 개성을 수렴해야 하는 학생회장으로서, 타의 귀감이 되기 위해 이렇게 입기 시작했답니다.","JPN":"私も生徒の多様性を受け入れるべき生徒会長として、\\n皆さんの模範になるためこのような服装になりました。","ENG":"So, as their representative, I started wearing clothes like these to show them that they can wear whatever they want to express their uniqueness.","TWN":"而作為必需包容學生不同個性的學生會長，就得以身作則才行，所以我才開始這樣穿的。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"오오! 그런 깊은 뜻이! 역시 사부!","JPN":"おぉ！　そんな深い意味が！　さすが師匠！","ENG":"Oooo! So thoughtful! Master, you're the best!","TWN":"噢噢！真是深奧！不愧是師父！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"음! 덕분에 본관 역시 수업 중에도 전투력을 유지하고 있다!","JPN":"うむ！　おかげで本官も授業中ですら戦闘力を維持している！","ENG":"Mm, thanks to you, I'm able to maintain my combat power even during class.","TWN":"嗯！得益於此，本官在上課時也會保持戰鬥力的！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그건 그렇고, 용무가 있어서 날 찾아왔다고 하지 않았던가요?","JPN":"ところで、用があって私を訪ねてきたのではないのですか？","ENG":"By the way, didn't you say you wanted to talk to me about something?","TWN":"好了，你們來找我不是有事嗎？"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"앗, 맞아!","JPN":"あっ、そうだ！","ENG":"Oh, that's right!","TWN":"啊，沒錯！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"사부도 요즘 도시에서 동물들이 실종되고 있다는 소문 들으셨어요?","JPN":"師匠、最近いろんなところで動物たちが行方不明になっている噂は聞きましたか？","ENG":"Master, have you heard that animals have been going missing from the city?","TWN":"師父也聽說了最近城市裡的動物不斷失蹤的消息吧？"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네, 학생회도 그 사건에 대해선 예의주시 중입니다.","JPN":"はい、生徒会もその事件を注視しています。","ENG":"Yes. The Student Council has been following the news.","TWN":"是的，學生會也在關注這件事情。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아끼는 애완동물이 사라진 학생들도 적지 않거든요.","JPN":"大切なペットがいなくなってしまった生徒も少なくないんです。","ENG":"Quite a few students of ours have lost their pet animals.","TWN":"不少學生的寵物也失蹤了。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"앗! 그럼 저희랑 같이 동물들을 찾는 걸 도와주시는 건가요?!","JPN":"あっ！　じゃあ、僕たちと一緒に動物を探してくれるんですか？","ENG":"Ooh, then could you help us find the animals?","TWN":"啊！那麼可以幫我們一起找回動物嗎？"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"물론 교내 동아리의 활동을 돕는 것 또한 학생회의 역할이긴 합니다만......","JPN":"もちろん、校内サークル活動を手伝うことも生徒会の役目なのですが……","ENG":"It's the Student Council's duty to assist student clubs in their activities,","TWN":"雖說支援校內社團的活動，也是學生會的職責……"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"학생회 임원들은 각자 맡은 역할로 바빠서 지원이 어려울 수도 있습니다.","JPN":"生徒会役員たちはそれぞれの役目を果たすために\\n忙しいので、支援が難しいかもしれません。","ENG":"but I don't know if its members have time to support you at this moment.","TWN":"但因為學生會的幹部都有各自要做的事情，所以支援可能會有困難。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"아앗, 아쉽다!","JPN":"ううっ、残念！","ENG":"Ack, that's a bummer.","TWN":"啊，好可惜喔！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"하지만 걱정 말아요.","JPN":"ですが、ご心配なく。","ENG":"But worry not.","TWN":"但不用擔心。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"모든 임원들이 나서지 못할 뿐, 도움이 필요한 학생들을 그냥 돌려보내진 않을 겁니다.","JPN":"全役員が支援することが無理なだけで、\\n助けが必要な生徒たちをそのまま帰らせたりなどはしません。","ENG":"I was speaking on behalf of the Council. You need help, and I'm not going to let you leave without it.","TWN":"我們只是無法讓所有幹部都參與其中，但不會讓需要幫助的學生空手而歸的。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"저라도 괜찮다면 여러분에게 도움을 드리기로 하죠.","JPN":"私でよろしければ、皆さんに協力します。","ENG":"I'll help you. If you want me, of course.","TWN":"如果你們不介意，我很願意幫助大家。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"정말요?","JPN":"本当ですか？","ENG":"Really?","TWN":"真的嗎？"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"와아! 감사합니다!","JPN":"わあ！　ありがとうございます！","ENG":"Yay! Thank you!","TWN":"哇！太感謝了！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그리고......","JPN":"そして……","ENG":"And...","TWN":"然後……"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이 일에 어울리는 한가한 적임자가 한 명 더 있어요.","JPN":"この仕事にぴったりの、暇をしている適任者がもう一人います。","ENG":"I know someone else who'd love to help you.","TWN":"還有一個人非常適合做這件事。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"으음......","JPN":"ううん……","ENG":"Mm...","TWN":"嗯……"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이디스는 학교의 방어시설과 전산시스템 관리를 책임지고 있어요.","JPN":"イーディスは学校の防御施設と\\nコンピューターシステム管理を担当しています。","ENG":"Edith is in charge of the Academy's defense and computer systems.","TWN":"伊蒂絲負責管理學校的防禦設施和電算系統。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"사실상 일거리가 가장 많이 쏟아지는 직책 중 하나라고 할 수 있죠.","JPN":"事実上、一番仕事が多い役員の一人と言えます。","ENG":"She's one of the busiest people in school.","TWN":"事實上，這可以說是工作最繁重的職責之一。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"네? 하지만 그냥 주무시고 계신데요?","JPN":"ええ？　でも、ただ寝てるだけのようですけど……","ENG":"Really? But she's asleep.","TWN":"是嗎？但她只是在睡覺耶？"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"대부분의 업무는 이디스가 만든 인공지능이 대신 수행해 주고 있거든요.","JPN":"イーディスの作った人工知能がほとんどの業務を代わりに遂行してるのです。","ENG":"Her AI is doing most of her work.","TWN":"大部分的工作會由伊蒂絲製作的人工智慧代為處理。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"얼핏 게을러 보일 수도 있지만, 실은 자기 역량으로 맡은 일을 훌륭히 해내고 있는 셈이죠.","JPN":"一見すると怠けてるように見えるかもしれませんが、\\n実際は自分の力で担当業務を見事にこなしているわけです。","ENG":"She may appear lazy because she's not doing anything, but it's her brain that matters.","TWN":"雖然看上去在偷懶，但她是用自己的力量，出色地完成了份內的工作。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"눈을 감고도 모두 해치울 수 있다니! 그야말로 고수의 경지! 멋지다!","JPN":"目をつぶっても全部できるとは！　まさに達人の境地！\\n素晴らしい！","ENG":"So, she can do things with her eyes closed! Not everyone can reach that state. Awesome!","TWN":"閉著眼睛還能處理所有工作！簡直就是高手的境界！太帥了！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"하지만 타의 모범이 되어야 할 학생회 임원이 한나절을 수면으로만 보내는 건 무척 비생산적이죠.","JPN":"しかし、皆さんの模範になるべき生徒会役員が\\n半日寝てるだけとは、とても非生産的ですね。","ENG":"Nevertheless, as a member of the Council, who should be setting an example for other students, she shouldn't spend all day sleeping.","TWN":"但必須成為他人榜樣的學生會幹部，整天卻只知道睡覺，這樣恐怕會有反效果。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"학생회장으로서 그냥 두고 볼 수는 없어요.","JPN":"生徒会長として見過ごすわけにはいきません。","ENG":"As the Student President, I can't let her do that, either.","TWN":"作為學生會長，我不能這樣坐視不管。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이디스? 잠깐 일어......","JPN":"イーディス？　ちょっと起き……","ENG":"Edith. Wake up—","TWN":"伊蒂絲？妳醒一……"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"식별되지 않은 위험개체의 접근을 감지. 자동 방어 시스템을 전개합니다.","JPN":"識別されていない危険個体の接近を感知。\\n自動防御システムを展開します。","ENG":"Unidentified threat detected. Initializing auto-defense system...","TWN":"偵測到未識別的危險個體靠近，啟動自動防禦系統。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AI_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MECHANIC_RAZANGRIFF_SKILL_START"},{"id":"L50_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"왓! 신기해! 의자가 말을 하잖아?","JPN":"うわっ！　すごい！　椅子がしゃべってる！","ENG":"Holy cow! Her chair can talk!","TWN":"哇！好神奇喔！椅子會說話耶？"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"그, 그게 중요한 게 아니라 미사일이 나오는 것 같은데요?!","JPN":"そ、それより、ミサイルが飛んできてますよ！？","ENG":"I-it can do more than that—it's producing a missile!","TWN":"那、那個不是重點，它好像要發射導彈了？！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_MECHANIC_GAMECHANGER_HYPER_SKILL_START"},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"다들 무사한가요?","JPN":"皆さん、無事ですか？","ENG":"Is everyone okay?","TWN":"大家沒事吧？"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"오오, 검으로 미사일을 전부 베어내다니! 굉장하다......","JPN":"おお、剣でミサイルを全部切っちゃうとは！　素晴らしい……","ENG":"Whoa, you cut down all the missiles with your sword! Super!","TWN":"喔喔，竟然用一把劍就把導彈全部斬斷了！好厲害……"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":" 엣취!","JPN":"くしゅん！","ENG":" Ah-choo!","TWN":"哈啾！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"콜록, 콜록! 미사일 안에 후춧가루가 들어 있었어!","JPN":"ゲホゲホ！　ミサイルの中に胡椒が入ってた！","ENG":"*Cough, cough* The missiles were filled with pepper!","TWN":"咳咳！導彈內放了胡椒粉！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"으아, 깜짝 놀랐어요......! 왜 그런 일이 일어난 거죠?","JPN":"うわぁ、びっくりしました……！　なんでこんなことが起きたんでしょう？","ENG":"Whoa, what a surprise! Why did that happen?","TWN":"哇啊，嚇我一跳……！為什麼會發生這種事？"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이디스가 만든 자동 반격 시스템이 오작동한 모양이군요.","JPN":"イーディスが作った自動反撃システムが誤作動を起こしたみたいですね。","ENG":"Edith's auto-defense system must have malfunctioned.","TWN":"好像是伊蒂絲製作的自動反擊系統啟動錯誤了。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아무래도, 인공지능이 저런 독특한 생명체에 대한 정보는 학습한 적이 없어서 벌어진 문제 같네요.","JPN":"どうやら、人工知能があんなに独特な生命体の情報を\\n学習しておらず生じた問題のようですね。","ENG":"The AI must not have seen such a unique life form before.","TWN":"看來是人工智慧沒有學習到這種獨特生命體的資訊，所以才會發生這樣的問題。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BEAR_SUMMON_NULL_NULL","text":{"KOREA":"삐?","JPN":"ピ？","ENG":"Beep?","TWN":"嗶？"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BEAR_SUMMON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BEAR_SUMMON_NULL_NULL","text":{"KOREA":"삐익......","JPN":"ピィィ……","ENG":"Beep...","TWN":"嗶……"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BEAR_SUMMON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"흐아암...... 시끄러워서 깨 버렸어......","JPN":"ふわぁ……うるさくて寝れないよ……","ENG":"*Yawn* Why is it so loud?","TWN":"哈啊……太吵害我醒過來了……"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"주르...... 지금 몇 시야......?","JPN":"J.O.U.R……今、何時……？","ENG":"J.O.U.R., what time is it right now?","TWN":"朱爾……現在幾點了……？"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"현재 시각 오전 11시. 취침 후 14시간 37분이 경과했습니다.","JPN":"現在の時刻午前11時。\\n就寝から14時間37分が経過しました。","ENG":"Current time, 11:00 a.m. It's been 14 hours and 37 minutes since you went to bed.","TWN":"現在時刻上午11點，就寢後已經過了14小時37分鐘。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_UI_DECK_UNIIT_SELECT"},{"id":"L25_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"아직 부족하잖아...... 일일 권장량 미만이라구...... 하아암......","JPN":"まだ足りないじゃん……\\n1日の目安量未満だよぅ……はああ……","ENG":"That's not enough. I need more sleep than that to function normally... *Yawn*","TWN":"這不是還不夠嗎……還沒有達到每日推薦的睡眠量……哈啊……"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이디스, 낮잠은 미뤄두고 도와줘야 할 일이 생겼어요.","JPN":"イーディス、昼寝の前に手伝ってほしいことがあります。","ENG":"Edith, you can sleep more later. For now, I need your help.","TWN":"伊蒂絲，先別睡了，有事情需要妳幫忙。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"으으, 조금만 더 있다가......","JPN":"うう、もうちょっと……","ENG":"Aww, not now...","TWN":"嗯嗯，我再睡一會兒……"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"아앗! 저 인형은 강습! 브레멘 동물전대의 잠꾸러기 펭귄, 안드레아스 소령!","JPN":"ああっ！　あの人形は、[強襲！ブレーメン動物戦隊]の\\n寝坊ペンギン、アンドレアス少佐！","ENG":"Gosh, that's Major Andreas, the sleepy penguin character from \\"Charge! Town Soldiers of Bremen!\\"","TWN":"啊啊！那個玩偶是強襲！布萊梅動物戰隊的瞌睡蟲企鵝，安德列斯少校！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"그것도 한정판으로 나왔던 반실물 사이즈!","JPN":"しかも、限定品として出た実物の半分サイズ！","ENG":"And it's even the limited-edition half life-size model!","TWN":"而且還是半實體大小的限定版耶！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"음?","JPN":"ん？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L36_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"오오, 브레멘 동물전대 아시는구나?","JPN":"おぉ、ブレーメン動物戦隊を知ってるんですねぇ？","ENG":"Oh, do you know Town Soldiers of Bremen?","TWN":"噢噢，妳也知道布萊梅動物戰隊？"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"물론이다. 본관은 주말 저녁마다 본방을 꼬박꼬박 챙겨보고 있지.","JPN":"もちろんだ。本官は毎週末の夜に放送を欠かさずに見ている。","ENG":"Absolutely. I never miss it each weekend.","TWN":"當然，本官每週末晚上都會看，一集都沒錯過。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"지난 주에 개봉한 극장판은 첫날 영화관에서 세 번 감상하고 DVD특전도 구매했다.","JPN":"先週公開した劇場版は公開初日に\\n映画館で3回鑑賞して、特典付きDVDも購入した。","ENG":"I even watched the movie version three times when it was first released, and I also bought the special DVD.","TWN":"上週上映的劇場版，我第一天就在電影院看了三次，還買了DVD特典。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"음! 안드레아스 소령이 주역으로 등장하는 영화 <color=#ffd34c>펭귄 이륙하다</color>는 시리즈들 사이에서도 명작 중의 명작이지!","JPN":"うん！　アンドレアス少佐が主人公として登場する\\n映画<color=#ffd34c>ペンギン、離陸する</color>は、シリーズの中でもトップの名作だね！","ENG":"Ah, <color=#ffd34c>The Penguin Flies</color> featuring Major Andreas as the main character is one of the best in the series.","TWN":"嗯！安德列斯少校以主角身份登場的電影<color=#ffd34c>企鵝起飛</color>，在系列中是神作中的神作！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L40_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"그 의견엔 전적으로 동의하는 바이다!","JPN":"その意見にはまったくもって同感だ！","ENG":"I couldn't agree more.","TWN":"我完全同意這個看法！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L41_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"언제나 동네북 취급을 당하던 안드레아스가 소대를 위해 각성해 멋지게 활약을 펼치는 모습은 정말 감동 그 자체였어!","JPN":"いつもいじめられてたアンドレアスが、小隊のために覚醒して\\nカッコよく活躍する姿は本当に感動した！","ENG":"Andreas, instead of being the usual laughingstock of the bunch, awakens to his power and fights for his friends. I love it.","TWN":"受氣包安德列斯為了小隊，覺醒後大放異彩的模樣真的超感動！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L42_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"헤헤~ 너 작품 보는 법을 좀 아는구나?","JPN":"へえ～。君、見る目があるねぇ。","ENG":"Teehee! So, you've got an eye for anime, huh?","TWN":"嘿嘿～妳眼光不錯嘛？"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"훗, 본관도 간만에 마음이 동하는 동지를 만난 것 같아서 무척 기쁘다!","JPN":"ふっ、本官も久々に意見が合う仲間に会えてとても嬉しい！","ENG":"Heh heh, I'm glad to have met a kindred spirit after so long.","TWN":"哼，能遇到志同道合的夥伴，本官也很高興！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"와아, 두 사람 벌써 엄청 친해진 것 같아요.","JPN":"わあ、二人とも既にとっても仲良しみたいですね。","ENG":"Wow, you guys sound like you're friends already.","TWN":"哇，你們兩個人已經打成一片了耶。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"덕심일체! 같은 취향으로 한 마음이 되면 의형제만큼이나 강한 유대로 이어지게 되지!","JPN":"オタク仲間！　同じ好みで気が合うと、\\n義兄弟同然の強い絆で結ばれるのよ！","ENG":"Anime fans forever! Nothing binds people together like sharing interests.","TWN":"趣味相投！擁有共同的興趣，可以形成堪比手足的關係！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"후훗, 아무래도 이디스에게 억지로 일을 시킬 필요는 없을 것 같군요.","JPN":"ふふっ、どうやらイーディスにむりやり仕事を\\nやらせる必要はないみたいですね。","ENG":"Hah hah. It seems I won't have to force Edith to join us.","TWN":"呵呵，看來這次不用強迫伊蒂絲做事情了。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"좋아, 내 도움이 필요하다고 했었지? 말해 봐~","JPN":"よし、私の助けが必要だと言ってたよねぇ？　言ってごら～ん？","ENG":"Alright, you said you needed my help. Tell me.","TWN":"好吧，你們需要我做什麼？說吧～"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"정말 귀여운 털뭉치로군요.","JPN":"本当に可愛いワンコですね。","ENG":"What a cute furball!","TWN":"好可愛的小毛團唷。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이런 아이들을 납치하는 자들이 있다니, 천인공노할 일입니다.","JPN":"こんなに可愛い動物をさらう者たちがいるなんて、到底許せませんね。","ENG":"I can't believe some people took away these cute little things from their owners.","TWN":"竟然會有人綁架這麼可愛的小傢伙，簡直是人神共憤。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"학생회의 이름을 걸고 반드시 동물친구들을 되찾아 드리도록 하죠.","JPN":"生徒会の名にかけて、必ず動物たちを助けてさしあげましょう。","ENG":"I swear on the honor of the Student Council that I'll help you find them at all costs.","TWN":"我以學生會的名義保證，一定會幫你們找回小動物。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"잘 부탁해, 사부!","JPN":"よろしくね、師匠！","ENG":"Thank you, Master!","TWN":"拜託妳了，師父！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"실종된 동물을 구하러 간다니 굉장해~ <color=#ffd34c>폭시 일병 구하기</color>의 한 장면 같잖아~","JPN":"行方不明になった動物を助けに行くなんて、すご～い。\\n<color=#ffd34c>プライベート・フォクシー</color>の一幕みた～い。","ENG":"This is awesome, going on a mission to find missing animals. It's just like <color=#ffd34c>Saving Private Foxy</color>!","TWN":"竟然要去解救失蹤的動物，太刺激了～根本就是<color=#ffd34c>拯救大兵狐狸</color>的那個場景嘛～"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"진정하도록! 이것은 놀이가 아니라 실전이다!","JPN":"落ち着け！　これは遊びではなく実戦だ！","ENG":"Calm yourself. This is not a game—it's a real situation!","TWN":"冷靜點！這不是遊戲，而是實戰！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"지금쯤 알렉산더는 포로수용소에 갇힌 채 두려움에 떨고 있을 거야.","JPN":"今頃、アレクサンダーは捕虜収容所に閉じ込められて\\n恐怖に震えているだろう。","ENG":"Alexander could be locked up in a POW camp, trembling with fear right now.","TWN":"可憐的亞歷山大現在應該被關在俘虜營裡，瑟瑟發抖著。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"야채 가게 할아버지 말로는 빵 봉투를 뒤집어 쓴 이상한 손님들이 알렉산더를 데려갔대.","JPN":"八百屋のおじいさんの話によると、紙袋をかぶった\\n変なお客さんたちがアレクサンダーを連れていったらしいよ。","ENG":"The greengrocer said some strange customers with bread bags over their heads took Alexander.","TWN":"蔬菜店的爺爺說，是一群頭上套著麵包袋的怪異客人帶走了亞歷山大。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"빵 봉투요......?","JPN":"紙袋ですか……？","ENG":"Bread bags?","TWN":"麵包袋……？"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"응. 할아버지가 알아차리고 쫓아갔는데 버려진 놀이동산 근처에서 사라졌다나 봐.","JPN":"うん。おじいさんが気づいて追いかけたけど、\\n遊園地の廃墟周辺で消えたらしいよ。","ENG":"Yes. When he realized they took his dog, he followed them. They disappeared near the abandoned theme park.","TWN":"嗯，爺爺發現後馬上追了上去，但他們在廢棄的遊樂場附近就不見了。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그럼 그 놀이동산부터 조사해 봐야겠네요.","JPN":"では、その遊園地から調べてみましょう。","ENG":"Then, we'd better check that theme park first.","TWN":"那就從那個遊樂場開始調查吧。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"단서를 찾으면 나한테 줘. 주르의 분석 시스템을 쓰면 알렉산더와 친구들이 어딨는지 알아낼 수 있을 거야.","JPN":"手がかりが見つかったら私にちょうだい。\\nJ.O.U.R.の分析システムを使えばアレクサンダーと友達の居場所がわかると思うよ。","ENG":"Let me know if you find any clues. I can use J.O.U.R.'s analysis system to locate Alexander and other animal pals.","TWN":"找到線索後就告訴我。只要使用朱爾的分析系統，應該就可以掌握亞歷山大和動物朋友們的位置。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"좋다! 애니멀 레스큐 스페셜포스, 통칭 A.R.S팀 출동!","JPN":"よし！\\nアニマルレスキュースペシャルフォース、通称A.R.Sチーム出動！","ENG":"Got it! Let's go, Animal Rescue Specialists, a.k.a. A.R.S.!","TWN":"好！動物救助特別搜查隊，A.R.S出動！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};